export const VOTING_CSS = "<style id=\"vote-widget-css\">\n.look-hero { position: relative; }\n.vote-look-inline { position: absolute; left: 18px; right: 18px; bottom: 18px; display: grid; grid-template-columns: minmax(0, 1fr) auto; align-items: center; gap: 0.75rem; padding: 0.68rem 0.72rem; background: rgba(255,255,252,0.88); border: 1px solid rgba(51,51,51,0.16); box-shadow: 0 16px 42px rgba(0,0,0,0.16); backdrop-filter: blur(14px) saturate(112%); }\n.vote-piece-inline { display: grid; grid-template-columns: minmax(150px, 1fr) auto; align-items: center; gap: 0.65rem; margin-top: 0.62rem; padding-top: 0.62rem; border-top: 1px solid rgba(51,51,51,0.12); }\n.vote-context { display: flex; align-items: center; gap: 0.5rem; min-width: 0; }\n.vote-live-dot { width: 7px; height: 7px; border-radius: 50%; background: #7c7c7c; flex: 0 0 auto; }\n.vote-live-dot.is-live { background: #2f6f3b; box-shadow: 0 0 0 5px rgba(47,111,59,0.12); }\n.vote-live-dot.is-hot { animation: votePing 900ms ease-out; }\n.vote-score { --vote-average: 50%; display: grid; grid-template-columns: max-content; align-items: start; gap: 0.24rem; min-width: 92px; width: max-content; max-width: 100%; transition: transform 0.16s ease; }\n.vote-score.hot { transform: translateY(-1px); }\n.score-counts { display: inline-flex; flex-wrap: wrap; align-items: baseline; gap: 0; min-width: 0; color: var(--bm-mute); }\n.score-pill { display: inline-flex; align-items: baseline; gap: 0.2rem; border: 0; background: transparent; padding: 0; font-size: 0.74rem; line-height: 1; color: inherit; white-space: nowrap; }\n.score-pill + .score-pill::before { content: \"/\"; margin: 0 0.38rem; color: #aaa49a; }\n.score-pill span { font-family: var(--bm-cond); font-weight: 700; font-size: 0.82rem; color: var(--bm-ink); }\n.score-up span { color: #667766; }\n.score-down span { color: #8b716b; }\n.vote-meter { grid-column: 1 / -1; position: relative; width: 100%; min-width: 92px; height: 5px; overflow: visible; background: linear-gradient(90deg, rgba(102,119,102,0.36) 0%, rgba(102,119,102,0.28) 49.5%, rgba(51,51,51,0.18) 49.5%, rgba(51,51,51,0.18) 50.5%, rgba(139,113,107,0.28) 50.5%, rgba(139,113,107,0.36) 100%); }\n.vote-meter-tick { position: absolute; left: var(--vote-average); top: -4px; bottom: -4px; width: 2px; background: #3f3c37; box-shadow: 0 0 0 1px rgba(255,255,252,0.9); transform: translateX(-1px); transition: left 180ms ease; }\n.vote-meter[data-empty=\"true\"] { background: rgba(51,51,51,0.12); }\n.vote-meter[data-empty=\"true\"] .vote-meter-tick { left: 50%; background: #8b877f; }\n.vote-rollover { grid-column: 1 / -1; position: relative; width: max-content; max-width: 100%; margin-top: 0.1rem; }\n.vote-rollover[hidden] { display: none; }\n.vote-rollover-trigger { border: 0; border-bottom: 1px solid currentColor; background: transparent; color: #7a766d; min-height: 0; padding: 0 0 0.08rem; font-family: var(--bm-cond); font-weight: 700; font-size: 0.68rem; letter-spacing: 0.06em; text-transform: uppercase; cursor: default; }\n.vote-rollover-panel { position: absolute; left: 0; top: calc(100% + 8px); z-index: 42; width: min(340px, calc(100vw - 32px)); max-height: 280px; overflow: auto; padding: 0.82rem; border: 1px solid rgba(51,51,51,0.16); background: #fffffc; box-shadow: 0 18px 50px rgba(0,0,0,0.15); opacity: 0; transform: translateY(-3px); visibility: hidden; pointer-events: none; transition: opacity 120ms ease, transform 120ms ease, visibility 120ms ease; }\n.vote-rollover:hover .vote-rollover-panel, .vote-rollover:focus-within .vote-rollover-panel { opacity: 1; transform: translateY(0); visibility: visible; pointer-events: auto; }\n.vote-look-inline .vote-rollover-panel { top: auto; bottom: calc(100% + 8px); }\n.vote-rollover-section + .vote-rollover-section { margin-top: 0.72rem; padding-top: 0.72rem; border-top: 1px solid var(--bm-line); }\n.vote-rollover-title { display: block; margin-bottom: 0.35rem; font-family: var(--bm-cond); font-weight: 700; font-size: 0.76rem; letter-spacing: 0.08em; text-transform: uppercase; color: var(--bm-ink); }\n.vote-rollover-list { list-style: none; margin: 0; padding: 0; display: grid; gap: 0.42rem; }\n.vote-rollover-list li { color: var(--bm-mute); font-size: 0.82rem; line-height: 1.3; }\n.vote-rollover-list b { color: var(--bm-ink); font-weight: 700; }\n.vote-rollover-note { display: block; margin-top: 0.12rem; color: var(--bm-mute); }\n.vote-choice { --vote-like: #3f754b; --vote-pass: #a05f57; display: inline-grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 0.48rem; flex: 0 0 auto; min-width: 174px; padding: 0; border: 0; background: transparent; box-shadow: none; }\n.thumb-btn { position: relative; border: 1px solid rgba(51,51,51,0.2); background: rgba(255,255,252,0.9); border-radius: 5px; color: #5f5b53; min-width: 82px; min-height: 36px; padding: 0 0.76rem; font-family: var(--bm-cond); font-weight: 700; font-size: 0.7rem; letter-spacing: 0.06em; line-height: 1; text-transform: uppercase; cursor: pointer; display: inline-flex; align-items: center; justify-content: center; gap: 0.38rem; box-shadow: inset 0 1px 0 rgba(255,255,252,0.96), 0 1px 2px rgba(28,28,28,0.04); user-select: none; -webkit-tap-highlight-color: transparent; transition: background 0.14s ease, border-color 0.14s ease, box-shadow 0.14s ease, color 0.14s ease, opacity 0.14s ease, transform 0.08s ease; }\n.thumb-btn::before { content: \"\"; width: 6px; height: 6px; border-radius: 50%; background: currentColor; opacity: 0.38; transform: scale(0.82); transition: opacity 0.14s ease, transform 0.14s ease; }\n.thumb-btn.up { color: var(--vote-like); border-color: rgba(63,117,75,0.28); background: rgba(63,117,75,0.045); }\n.thumb-btn.down { color: var(--vote-pass); border-color: rgba(160,95,87,0.28); background: rgba(160,95,87,0.045); }\n.thumb-btn:hover { background: #fffffc; color: #2f2d29; border-color: rgba(51,51,51,0.36); box-shadow: inset 0 1px 0 rgba(255,255,252,0.96), 0 2px 5px rgba(28,28,28,0.08); }\n.thumb-btn.up:hover { border-color: rgba(63,117,75,0.58); background: rgba(63,117,75,0.13); color: var(--vote-like); }\n.thumb-btn.down:hover { border-color: rgba(160,95,87,0.58); background: rgba(160,95,87,0.13); color: var(--vote-pass); }\n.thumb-btn:focus-visible { outline: 2px solid rgba(47,111,59,0.24); outline-offset: 2px; }\n.thumb-btn:active { transform: scale(0.96); }\n.thumb-btn.up.on { background: rgba(63,117,75,0.22); border-color: rgba(63,117,75,0.68); color: var(--vote-like); box-shadow: 0 1px 2px rgba(28,28,28,0.05), inset 0 0 0 1px rgba(255,255,252,0.64); }\n.thumb-btn.down.on { background: rgba(160,95,87,0.22); border-color: rgba(160,95,87,0.68); color: var(--vote-pass); box-shadow: 0 1px 2px rgba(28,28,28,0.05), inset 0 0 0 1px rgba(255,255,252,0.64); }\n.thumb-btn.on::before { opacity: 0.9; transform: scale(1); }\n.thumb-btn.dim { opacity: 0.64; }\n.vote-dock { position: fixed; left: 50%; right: auto; bottom: 18px; width: min(960px, calc(100vw - 32px)); z-index: 30; display: grid; grid-template-columns: minmax(130px, 0.62fr) minmax(150px, 0.62fr) minmax(220px, 1fr) auto; gap: 0.55rem; align-items: center; padding: 0.62rem 2.4rem 0.62rem 0.62rem; border: 1px solid rgba(51,51,51,0.16); background: rgba(255,255,252,0.92); box-shadow: 0 20px 60px rgba(0,0,0,0.2); backdrop-filter: blur(18px) saturate(110%); transform: translate(-50%, calc(100% + 28px)); opacity: 0; pointer-events: none; transition: transform 180ms ease, opacity 180ms ease; }\n.vote-dock.is-open { transform: translate(-50%, 0); opacity: 1; pointer-events: auto; }\n.vote-dock:focus-within { border-color: rgba(51,51,51,0.32); }\n.vote-dock-close { position: absolute; top: 0.4rem; right: 0.42rem; width: 30px; height: 30px; border: 0; background: transparent; color: #777168; display: inline-flex; align-items: center; justify-content: center; font-family: var(--bm-cond); font-weight: 700; font-size: 1.28rem; line-height: 1; cursor: pointer; transition: background 120ms ease, color 120ms ease; }\n.vote-dock-close:hover, .vote-dock-close:focus-visible { background: rgba(51,51,51,0.08); color: var(--bm-ink); outline: 0; }\n.vote-dock-summary { display: grid; gap: 0.08rem; min-width: 0; }\n.vote-dock-kicker { display: flex; align-items: center; gap: 0.38rem; font-family: var(--bm-cond); font-size: 0.74rem; font-weight: 700; letter-spacing: 0.08em; text-transform: uppercase; color: var(--bm-ink); white-space: nowrap; }\n.vote-dock-sub { font-size: 0.78rem; color: var(--bm-mute); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n.vote-name, .vote-comment { width: 100%; min-width: 0; min-height: 38px; border: 1px solid rgba(51,51,51,0.16); background: rgba(255,255,255,0.86); color: var(--bm-ink); padding: 0.56rem 0.68rem; font: inherit; }\n.vote-name:focus, .vote-comment:focus { outline: 1px solid rgba(51,51,51,0.45); outline-offset: -1px; }\n.vote-submit { min-height: 38px; border: 0; background: var(--bm-ink); color: #fff; padding: 0 1rem; font-family: var(--bm-cond); font-weight: 700; font-size: 0.76rem; letter-spacing: 0.08em; text-transform: uppercase; cursor: pointer; white-space: nowrap; }\n.vote-submit:hover { background: #111; }\n.vote-submit[disabled] { background: #999; cursor: default; }\n.vote-status { grid-column: 2 / -1; min-height: 0; font-size: 0.8rem; color: var(--bm-mute); }\n.vote-status:empty { display: none; }\n.vote-status.ok { color: #2a7c2a; }\n.vote-status.err { color: #b03030; }\n.vote-toast { position: fixed; left: 50%; bottom: 92px; z-index: 31; transform: translate(-50%, 10px); opacity: 0; pointer-events: none; background: #1c1c1c; color: #fff; padding: 0.55rem 0.8rem; font-family: var(--bm-cond); font-weight: 700; font-size: 0.74rem; letter-spacing: 0.08em; text-transform: uppercase; transition: opacity 160ms ease, transform 160ms ease; }\n.vote-toast.is-on { opacity: 1; transform: translate(-50%, 0); }\nbody.vote-dock-open .page { padding-bottom: 150px; }\nbody.vote-cart-open .vote-dock { bottom: 96px; }\nbody.vote-cart-open .vote-toast { bottom: 170px; }\nbody.vote-dock-open.vote-cart-open .page { padding-bottom: 250px; }\n@keyframes votePing { 0% { box-shadow: 0 0 0 0 rgba(47,111,59,0.35); } 100% { box-shadow: 0 0 0 14px rgba(47,111,59,0); } }\n@media (max-width: 1023px) {\n  .vote-dock { grid-template-columns: minmax(0, 1fr) minmax(0, 1fr) auto; }\n  .vote-dock-summary { grid-column: 1 / -1; grid-template-columns: auto minmax(0, 1fr); column-gap: 0.75rem; align-items: baseline; }\n  .vote-status { grid-column: 1 / -1; }\n}\n@media (max-width: 699px) {\n  .vote-look-inline { position: static; margin-top: 0.65rem; grid-template-columns: 1fr; gap: 0.82rem; padding: 0.78rem 0.82rem; box-shadow: none; background: #fbfaf7; }\n  .vote-piece-inline { grid-template-columns: 1fr; }\n  .vote-context { display: grid; grid-template-columns: auto minmax(0, 1fr); align-items: start; column-gap: 0.58rem; width: 100%; }\n  .vote-piece-inline .vote-context { display: block; }\n  .vote-live-dot { width: 6px; height: 6px; margin-top: 0.45rem; }\n  .vote-live-dot.is-live { box-shadow: 0 0 0 4px rgba(47,111,59,0.12); }\n  .vote-score { width: 100%; min-width: 0; max-width: none; grid-template-columns: minmax(0, 1fr); gap: 0.34rem; }\n  .score-counts { width: 100%; font-size: 0.8rem; }\n  .score-pill span { font-size: 0.92rem; }\n  .vote-meter { min-width: 0; height: 6px; }\n  .vote-meter-tick { top: -5px; bottom: -5px; }\n  .vote-choice { width: 100%; }\n  .thumb-btn { min-height: 42px; min-width: 0; }\n  .vote-dock { left: 8px; right: 8px; width: auto; bottom: 8px; grid-template-columns: 1fr; gap: 0.5rem; padding: 0.72rem 2.45rem 0.72rem 0.72rem; transform: translateY(calc(100% + 28px)); }\n  .vote-dock.is-open { transform: translateY(0); }\n  .vote-dock-close { top: 0.42rem; right: 0.48rem; }\n  .vote-dock-summary { grid-template-columns: 1fr; }\n  .vote-status { grid-column: auto; }\n  .vote-toast { bottom: 164px; width: max-content; max-width: calc(100vw - 32px); text-align: center; }\n  body.vote-dock-open .page { padding-bottom: 280px; }\n  body.vote-cart-open .vote-dock { bottom: 80px; }\n  body.vote-cart-open .vote-toast { bottom: 236px; }\n  body.vote-dock-open.vote-cart-open .page { padding-bottom: 360px; }\n}\n</style>" as const
export const VOTE_DOCK = "<!-- VOTE-DOCK -->\n<form class=\"vote-dock\" id=\"vote-form\" hidden>\n  <button class=\"vote-dock-close\" id=\"vote-dock-close\" type=\"button\" aria-label=\"Close name and note footer\" title=\"Close\">&times;</button>\n  <div class=\"vote-dock-summary\" id=\"vote-live\">\n    <span class=\"vote-dock-kicker\"><span class=\"vote-live-dot\"></span><strong id=\"live-vote-count\">0 votes</strong></span>\n    <span class=\"vote-dock-sub\" id=\"live-updated\">Connecting...</span>\n  </div>\n  <input class=\"vote-name\" name=\"voter\" placeholder=\"Name (optional)\" maxlength=\"60\">\n  <input class=\"vote-comment\" name=\"comment\" placeholder=\"Note (optional)\" maxlength=\"1000\">\n  <button class=\"vote-submit\" type=\"submit\">Save name/note</button>\n  <div class=\"vote-status\" id=\"vote-status\" aria-live=\"polite\"></div>\n</form>\n<div class=\"vote-toast\" id=\"vote-toast\" hidden></div>\n<!-- /VOTE-DOCK -->" as const
export const VOTE_WIDGET_SCRIPT = "<script id=\"vote-widget-js\">\n(() => {\n  const VOTE_LOOKBOOK_ID = (typeof LOOKBOOK_ID !== 'undefined' ? LOOKBOOK_ID : location.pathname);\n  const submittedKey = `buckmason:voted:${VOTE_LOOKBOOK_ID}`;\n  const ballotIdKey = `buckmason:vote-ballot-id:${VOTE_LOOKBOOK_ID}`;\n  const ballotKey = `buckmason:vote-ballot:${VOTE_LOOKBOOK_ID}`;\n  const voterNameKey = 'buckmason:voter-name';\n  const dock = document.getElementById('vote-form');\n  const liveCount = document.getElementById('live-vote-count');\n  const liveUpdated = document.getElementById('live-updated');\n  const toast = document.getElementById('vote-toast');\n  const cartBar = document.getElementById('cart-bar');\n  const lastTotals = new Map();\n  let lastVoteCount = null;\n  let currentTally = null;\n  let pollTimer = null;\n  let pollMs = 8000;\n  let liveSocket = null;\n  let liveSocketTimer = null;\n  let liveSocketAttempts = 0;\n  let toastTimer = null;\n  let saveTimer = null;\n  let dockDismissed = false;\n  const pendingTargets = new Map();\n  const ballotId = getBallotId();\n\n  document.querySelectorAll('.vote-choice').forEach(group => {\n    group.querySelectorAll('.thumb-btn').forEach(btn => {\n      btn.addEventListener('click', event => {\n        event.preventDefault();\n        event.stopPropagation();\n        const current = group.dataset.value || '';\n        const clicked = btn.dataset.vote;\n        const next    = (current === clicked) ? '' : clicked;\n        const displayed = displayedBucketFor(group);\n        applyChoice(group, next);\n        markPendingTarget(group, displayed, current, next);\n        renderOptimisticScore(group);\n        dockDismissed = false;\n        updateDockState(true);\n        queueSave('choice');\n      });\n    });\n  });\n\n  function plural(n, one, many) { return `${n} ${n === 1 ? one : many}`; }\n  function getBallotId() {\n    let id = localStorage.getItem(ballotIdKey);\n    if (!id) {\n      const randomId = (typeof crypto !== 'undefined' && crypto.randomUUID)\n        ? crypto.randomUUID()\n        : `${Date.now()}-${Math.random().toString(36).slice(2)}`;\n      id = randomId.replace(/[^A-Za-z0-9_-]/g, '');\n      localStorage.setItem(ballotIdKey, id);\n    }\n    return id;\n  }\n  function syncCartBarState() {\n    document.body.classList.toggle('vote-cart-open', !!cartBar?.classList.contains('show'));\n  }\n  function applyChoice(group, value) {\n    group.dataset.value = value || '';\n    group.querySelectorAll('.thumb-btn').forEach(b => {\n      const isOn = b.dataset.vote === group.dataset.value && group.dataset.value !== '';\n      b.classList.toggle('on', isOn);\n      b.classList.toggle('dim', group.dataset.value !== '' && !isOn);\n      b.dataset.state = isOn ? 'on' : 'off';\n      b.setAttribute('aria-pressed', isOn ? 'true' : 'false');\n    });\n  }\n  function markSavedChoices(payload) {\n    document.querySelectorAll('.vote-choice').forEach(g => {\n      const saved = g.dataset.kind === 'look'\n        ? (payload.looks || {})[g.dataset.id]\n        : (payload.items || {})[g.dataset.id];\n      g.dataset.savedValue = saved || '';\n    });\n  }\n  function selectedGroups() { return [...document.querySelectorAll('.vote-choice')].filter(g => g.dataset.value); }\n  function groupFor(kind, id) {\n    return [...document.querySelectorAll('.vote-choice')].find(g => g.dataset.kind === kind && g.dataset.id === id);\n  }\n  function collectVotes() {\n    const looks = {}, items = {};\n    document.querySelectorAll('.vote-choice').forEach(g => {\n      if (!g.dataset.value) return;\n      if (g.dataset.kind === 'look') looks[g.dataset.id] = g.dataset.value;\n      else                            items[g.dataset.id] = g.dataset.value;\n    });\n    return { looks, items };\n  }\n  function buildPayload() {\n    return {\n      ballot_id: ballotId,\n      voter: (dock?.voter?.value || '').trim(),\n      comment: (dock?.comment?.value || '').trim(),\n      ...collectVotes(),\n    };\n  }\n  function hasSavedServerBallot() {\n    return !!localStorage.getItem(submittedKey) || !!localStorage.getItem(ballotKey);\n  }\n  function hasBallotContent(payload) {\n    return Object.keys(payload.looks || {}).length > 0 ||\n      Object.keys(payload.items || {}).length > 0 ||\n      !!payload.voter || !!payload.comment ||\n      hasSavedServerBallot();\n  }\n  function restoreSavedVote() {\n    let saved = null;\n    try { saved = JSON.parse(localStorage.getItem(ballotKey) || 'null'); } catch {}\n    const savedName = localStorage.getItem(voterNameKey) || saved?.voter || '';\n    if (dock?.voter && savedName) dock.voter.value = savedName;\n    if (dock?.comment && saved?.comment) dock.comment.value = saved.comment;\n\n    for (const [look, value] of Object.entries(saved?.looks || {})) {\n      const group = groupFor('look', look);\n      if (group) applyChoice(group, value);\n    }\n    for (const [sku, value] of Object.entries(saved?.items || {})) {\n      const group = groupFor('item', sku);\n      if (group) applyChoice(group, value);\n    }\n    if (saved) markSavedChoices(saved);\n    if (saved && (Object.keys(saved.looks || {}).length || Object.keys(saved.items || {}).length)) {\n      dock?.classList.add('was-submitted');\n      const status = document.getElementById('vote-status');\n      if (status) status.textContent = 'Restored your saved likes and passes from this browser.';\n      const btn = dock?.querySelector('.vote-submit');\n      if (btn) btn.textContent = 'Save name/note';\n    }\n  }\n  function saveLocalBallot(payload, ts) {\n    const savedAt = ts || new Date().toISOString();\n    if (ts) localStorage.setItem(submittedKey, savedAt);\n    localStorage.setItem(voterNameKey, payload.voter || '');\n    localStorage.setItem(ballotKey, JSON.stringify({\n      ballot_id: ballotId,\n      voter: payload.voter || '',\n      comment: payload.comment || '',\n      looks: payload.looks || {},\n      items: payload.items || {},\n      ts: savedAt,\n    }));\n  }\n  async function postBallot(payload, reason = 'manual') {\n    if (!hasBallotContent(payload)) return;\n    const status = document.getElementById('vote-status');\n    const btn = dock?.querySelector('.vote-submit');\n    if (status) {\n      status.className = 'vote-status';\n      status.textContent = reason === 'choice' ? 'Saving your vote...' : 'Saving name/note...';\n    }\n    if (btn && reason !== 'choice') btn.disabled = true;\n    try {\n      const r = await fetch('/api/vote', {\n        method: 'POST',\n        headers: {'content-type':'application/json'},\n        body: JSON.stringify(payload),\n      });\n      const j = await r.json();\n      if (!j.ok) throw new Error(j.error || 'unknown error');\n      saveLocalBallot(payload, j.ts);\n      markSavedChoices(payload);\n      markPendingPosted(payload);\n      dock?.classList.add('was-submitted');\n      if (status) {\n        status.className = 'vote-status ok';\n        status.textContent = reason === 'choice'\n          ? 'Saved. Add your name or a note anytime.'\n          : 'Saved name/note.';\n      }\n      if (btn) {\n        btn.disabled = false;\n        btn.textContent = reason === 'choice' ? 'Save name/note' : 'Saved';\n        if (reason !== 'choice') setTimeout(() => { btn.textContent = 'Save name/note'; }, 1200);\n      }\n      refreshVotes({ fresh: true });\n    } catch (err) {\n      if (status) {\n        status.className='vote-status err';\n        status.textContent='Error: '+err.message;\n      }\n      if (btn) btn.disabled = false;\n    }\n  }\n  function queueSave(reason = 'choice') {\n    const payload = buildPayload();\n    saveLocalBallot(payload);\n    clearTimeout(saveTimer);\n    saveTimer = setTimeout(() => postBallot(buildPayload(), reason), 350);\n  }\n  function updateDockState(openOnSelection = false) {\n    const count = selectedGroups().length;\n    if (!dock) return;\n    const hasDockContext = count > 0 || dock.classList.contains('was-submitted');\n    const shouldOpen = hasDockContext && !dockDismissed;\n    if (openOnSelection || shouldOpen) {\n      dock.hidden = false;\n      requestAnimationFrame(() => {\n        dock.classList.toggle('is-open', shouldOpen);\n        document.body.classList.toggle('vote-dock-open', shouldOpen);\n      });\n    }\n    if (!shouldOpen) {\n      dock.classList.remove('is-open');\n      document.body.classList.remove('vote-dock-open');\n    }\n  }\n  function dismissDock() {\n    dockDismissed = true;\n    if (!dock) return;\n    dock.classList.remove('is-open');\n    document.body.classList.remove('vote-dock-open');\n  }\n  function bucketFor(data, kind, id) {\n    const source = kind === 'look' ? data?.tally?.looks : data?.tally?.items;\n    return source?.[id] || { up: 0, down: 0, total: 0, score: 0 };\n  }\n  function targetKey(kind, id) {\n    return `${kind}:${id}`;\n  }\n  function cloneBucket(bucket) {\n    return {\n      ...(bucket || {}),\n      up: Number(bucket.up || 0),\n      down: Number(bucket.down || 0),\n      up_voters: [...(bucket.up_voters || [])],\n      down_voters: [...(bucket.down_voters || [])],\n    };\n  }\n  function finishBucket(bucket) {\n    bucket.up = Math.max(0, Number(bucket.up || 0));\n    bucket.down = Math.max(0, Number(bucket.down || 0));\n    bucket.total = bucket.up + bucket.down;\n    bucket.score = bucket.up - bucket.down;\n    return bucket;\n  }\n  function displayedBucketFor(group) {\n    const node = scoreNodeFor(group.dataset.kind, group.dataset.id);\n    return {\n      up: Number(node?.querySelector('[data-up]')?.textContent || 0),\n      down: Number(node?.querySelector('[data-down]')?.textContent || 0),\n      up_voters: [],\n      down_voters: [],\n    };\n  }\n  function markPendingTarget(group, displayed, previous, next) {\n    const bucket = cloneBucket(displayed || {});\n    if (previous === 'up') bucket.up -= 1;\n    if (previous === 'down') bucket.down -= 1;\n    if (next === 'up') bucket.up += 1;\n    if (next === 'down') bucket.down += 1;\n    pendingTargets.set(targetKey(group.dataset.kind, group.dataset.id), {\n      ...finishBucket(bucket),\n      posted: false,\n      ts: Date.now(),\n    });\n  }\n  function markPendingPosted(payload) {\n    let marked = false;\n    for (const look of Object.keys(payload.looks || {})) {\n      const pending = pendingTargets.get(targetKey('look', look));\n      if (pending) pending.posted = true;\n      marked = true;\n    }\n    for (const sku of Object.keys(payload.items || {})) {\n      const pending = pendingTargets.get(targetKey('item', sku));\n      if (pending) pending.posted = true;\n      marked = true;\n    }\n    if (!marked) pendingTargets.forEach(pending => { pending.posted = true; });\n  }\n  function pendingBucket(kind, id, bucket) {\n    const pending = pendingTargets.get(targetKey(kind, id));\n    if (!pending) return null;\n    const server = finishBucket(cloneBucket(bucket || {}));\n    const age = Date.now() - pending.ts;\n    if ((pending.posted && age > 750 && server.up === pending.up && server.down === pending.down) || age > 12000) {\n      pendingTargets.delete(targetKey(kind, id));\n      return null;\n    }\n    return {\n      ...server,\n      up: pending.up,\n      down: pending.down,\n      total: pending.total,\n      score: pending.score,\n    };\n  }\n  function optimisticBucket(kind, id, bucket) {\n    const group = groupFor(kind, id);\n    if (!group) return bucket;\n    const pending = pendingBucket(kind, id, bucket);\n    if (pending) return pending;\n    const saved = group.dataset.savedValue || '';\n    const current = group.dataset.value || '';\n    if (saved === current) return bucket;\n    const next = cloneBucket(bucket || {});\n    if (saved === 'up') next.up = Math.max(0, next.up - 1);\n    if (saved === 'down') next.down = Math.max(0, next.down - 1);\n    if (current === 'up') next.up += 1;\n    if (current === 'down') next.down += 1;\n    return finishBucket(next);\n  }\n  function renderOptimisticScore(group) {\n    const node = scoreNodeFor(group.dataset.kind, group.dataset.id);\n    if (!node) return;\n    const bucket = bucketFor(currentTally, group.dataset.kind, group.dataset.id);\n    renderScore(node, optimisticBucket(group.dataset.kind, group.dataset.id, bucket));\n  }\n  function scoreNodeFor(kind, id) {\n    return Array.from(document.querySelectorAll('.vote-score')).find(node =>\n      node.dataset.scoreKind === kind && node.dataset.scoreId === id\n    );\n  }\n  function averagePosition(up, total) {\n    if (!total) return '50%';\n    const pct = Math.max(0, Math.min(100, Math.round((1 - (Number(up || 0) / total)) * 1000) / 10));\n    return `${Number.isInteger(pct) ? pct.toFixed(0) : pct.toFixed(1)}%`;\n  }\n  function renderScore(node, bucket) {\n    const up = Number(bucket.up || 0);\n    const down = Number(bucket.down || 0);\n    const total = up + down;\n    const key = `${node.dataset.scoreKind}:${node.dataset.scoreId}`;\n    const previousTotal = lastTotals.get(key);\n    if (previousTotal !== undefined && previousTotal !== total) {\n      node.classList.add('hot');\n      setTimeout(() => node.classList.remove('hot'), 900);\n    }\n    lastTotals.set(key, total);\n    node.querySelector('[data-up]').textContent = up;\n    node.querySelector('[data-down]').textContent = down;\n    node.dataset.empty = total ? 'false' : 'true';\n    node.style.setProperty('--vote-average', averagePosition(up, total));\n    const meter = node.querySelector('[data-vote-meter]');\n    if (meter) {\n      meter.dataset.empty = total ? 'false' : 'true';\n      meter.setAttribute('aria-label', total ? `${up} like, ${down} pass` : 'No votes yet');\n    }\n    const rollover = node.querySelector('[data-vote-rollover]');\n    const trigger = node.querySelector('[data-rollover-trigger]');\n    const panel = node.querySelector('[data-rollover-panel]');\n    const upVoters = bucket.up_voters || [];\n    const downVoters = bucket.down_voters || [];\n    const detailCount = upVoters.length + downVoters.length;\n    if (rollover && trigger && panel) {\n      rollover.hidden = detailCount === 0;\n      trigger.textContent = plural(detailCount, 'voter', 'voters');\n      trigger.setAttribute('aria-label', `Show ${plural(detailCount, 'named vote', 'named votes')} and notes`);\n      panel.innerHTML = renderRollover(upVoters, downVoters);\n    }\n    node.title = total ? `${up} like, ${down} pass` : 'No votes yet';\n  }\n  function escapeHtml(value) {\n    return String(value).replace(/[&<>\"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',\"'\":'&#39;'}[c]));\n  }\n  function renderRollover(upVoters, downVoters) {\n    return [\n      voterSection('Like', upVoters),\n      voterSection('Pass', downVoters),\n    ].filter(Boolean).join('');\n  }\n  function voterSection(label, voters) {\n    if (!voters?.length) return '';\n    const rows = voters.map(v => {\n      const note = (v.comment || '').trim();\n      return `<li><b>${escapeHtml(v.voter || 'anonymous')}</b>${note ? `<span class=\"vote-rollover-note\">${escapeHtml(note)}</span>` : ''}</li>`;\n    }).join('');\n    return `<section class=\"vote-rollover-section\"><strong class=\"vote-rollover-title\">${label}</strong><ul class=\"vote-rollover-list\">${rows}</ul></section>`;\n  }\n  function showToast(message) {\n    if (!toast) return;\n    toast.textContent = message;\n    toast.hidden = false;\n    requestAnimationFrame(() => toast.classList.add('is-on'));\n    clearTimeout(toastTimer);\n    toastTimer = setTimeout(() => {\n      toast.classList.remove('is-on');\n      setTimeout(() => { toast.hidden = true; }, 180);\n    }, 2200);\n  }\n  function renderLive(data) {\n    const incomingGeneratedAt = Date.parse(data?.tally?.generated_at || '');\n    const currentGeneratedAt = Date.parse(currentTally?.tally?.generated_at || '');\n    if (\n      Number.isFinite(incomingGeneratedAt) &&\n      Number.isFinite(currentGeneratedAt) &&\n      incomingGeneratedAt < currentGeneratedAt\n    ) return;\n    currentTally = data;\n    const count = Number(data?.tally?.count || 0);\n    liveCount.textContent = plural(count, 'vote', 'votes');\n    liveUpdated.textContent = data?.tally?.last_vote_ts\n      ? `Updated ${new Date(data.tally.last_vote_ts).toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' })}`\n      : 'Waiting for first vote';\n    document.querySelectorAll('.vote-live-dot').forEach(dot => dot.classList.add('is-live'));\n    if (lastVoteCount !== null && count > lastVoteCount) {\n      const diff = count - lastVoteCount;\n      document.querySelectorAll('.vote-live-dot').forEach(dot => dot.classList.add('is-hot'));\n      liveUpdated.textContent = plural(diff, 'new vote', 'new votes');\n      showToast(plural(diff, 'new vote just landed', 'new votes just landed'));\n      setTimeout(() => document.querySelectorAll('.vote-live-dot').forEach(dot => dot.classList.remove('is-hot')), 900);\n    }\n    lastVoteCount = count;\n    document.querySelectorAll('.vote-score').forEach(node => {\n      const bucket = bucketFor(data, node.dataset.scoreKind, node.dataset.scoreId);\n      renderScore(node, optimisticBucket(node.dataset.scoreKind, node.dataset.scoreId, bucket));\n    });\n  }\n  function scheduleNext() {\n    clearTimeout(pollTimer);\n    const base = document.hidden ? 20000 : pollMs;\n    pollTimer = setTimeout(() => refreshVotes(), base + Math.round(Math.random() * 1800));\n  }\n  async function refreshVotes(opts = {}) {\n    try {\n      const endpoint = opts.fresh ? '/api/votes?public=1&fresh=1' : '/api/votes?public=1';\n      const r = await fetch(endpoint, { headers: { 'accept': 'application/json' } });\n      if (!r.ok) throw new Error(`status ${r.status}`);\n      const data = await r.json();\n      if (data.ok) renderLive(data);\n      pollMs = 8000;\n    } catch (err) {\n      if (liveUpdated) liveUpdated.textContent = 'Reconnecting…';\n      pollMs = Math.min(30000, Math.round(pollMs * 1.6));\n    } finally {\n      scheduleNext();\n    }\n  }\n  function liveVotesUrl() {\n    const protocol = location.protocol === 'https:' ? 'wss:' : 'ws:';\n    return `${protocol}//${location.host}/api/votes/live`;\n  }\n  function connectLiveVotes() {\n    if (typeof WebSocket === 'undefined') return;\n    if (\n      liveSocket &&\n      (liveSocket.readyState === WebSocket.OPEN || liveSocket.readyState === WebSocket.CONNECTING)\n    ) return;\n    try {\n      liveSocket = new WebSocket(liveVotesUrl());\n    } catch {\n      scheduleLiveReconnect();\n      return;\n    }\n    liveSocket.addEventListener('open', () => {\n      liveSocketAttempts = 0;\n      if (liveUpdated && !currentTally) liveUpdated.textContent = 'Live updates on';\n    });\n    liveSocket.addEventListener('message', event => {\n      let data = null;\n      try { data = JSON.parse(event.data || 'null'); } catch {}\n      if (data?.type === 'tally' && data.ok) {\n        pollMs = 8000;\n        renderLive(data);\n      } else if (data?.type === 'vote' || data?.type === 'refresh') {\n        refreshVotes();\n      }\n    });\n    liveSocket.addEventListener('close', scheduleLiveReconnect);\n    liveSocket.addEventListener('error', () => {\n      try { liveSocket?.close(); } catch {}\n    });\n  }\n  function scheduleLiveReconnect() {\n    if (document.hidden) return;\n    liveSocket = null;\n    clearTimeout(liveSocketTimer);\n    const delay = Math.min(30000, 1200 * Math.pow(1.7, liveSocketAttempts));\n    liveSocketAttempts += 1;\n    if (liveUpdated) liveUpdated.textContent = 'Live updates reconnecting...';\n    liveSocketTimer = setTimeout(connectLiveVotes, delay + Math.round(Math.random() * 500));\n  }\n\n  document.getElementById('vote-form')?.addEventListener('submit', async e => {\n    e.preventDefault();\n    await postBallot(buildPayload(), 'manual');\n  });\n  document.getElementById('vote-dock-close')?.addEventListener('click', e => {\n    e.preventDefault();\n    dismissDock();\n  });\n\n  dock?.voter?.addEventListener('input', () => {\n    const payload = buildPayload();\n    saveLocalBallot(payload);\n  });\n  dock?.comment?.addEventListener('input', () => {\n    saveLocalBallot(buildPayload());\n  });\n\n  restoreSavedVote();\n  syncCartBarState();\n  if (cartBar && typeof MutationObserver !== 'undefined') {\n    new MutationObserver(syncCartBarState).observe(cartBar, { attributes: true, attributeFilter: ['class'] });\n  }\n  if (localStorage.getItem(submittedKey) && !localStorage.getItem(ballotKey)) {\n    const status = document.getElementById('vote-status');\n    if (status) status.textContent = 'This browser has already submitted a vote.';\n  }\n  updateDockState(false);\n  document.addEventListener('visibilitychange', () => {\n    if (!document.hidden) {\n      refreshVotes({ fresh: true });\n      connectLiveVotes();\n    }\n  });\n  refreshVotes();\n  connectLiveVotes();\n})();\n</script>" as const
export const FAVICON_TAGS = "  <link rel=\"icon\" type=\"image/png\" sizes=\"32x32\" href=\"favicon-32.png\">\n  <link rel=\"icon\" type=\"image/png\" sizes=\"16x16\" href=\"favicon-16.png\">\n  <link rel=\"apple-touch-icon\" sizes=\"180x180\" href=\"apple-touch-icon.png\">\n  <link rel=\"shortcut icon\" href=\"favicon.ico\">" as const
export const VOTE_POST_FUNCTION = "// POST /api/vote — upserts one browser ballot to the bound KV namespace.\n//\n// Body (JSON):\n//   {\n//     ballot_id:string,                 // stable browser-local id\n//     voter:    string,                 // 0..60 chars; defaults anonymous\n//     comment:  string,                 // 0..1000 chars\n//     looks:    { lookN: \"up\"|\"down\" }, // optional per-look thumbs\n//     items:    { <sku>: \"up\"|\"down\" }  // optional per-item thumbs (by SKU)\n//   }\n//\n// Required bindings:\n//   env.LOOKBOOK_VOTES   KV namespace (see wrangler.toml.example)\n//   env.LOOKBOOK_ID      string var — uniquely identifies this lookbook so the\n//                        same KV namespace can be shared across deployments.\n//\n// Stored key shape: vote:<lookbook_id>:ballot:<ballot_id>\n// Stored value:     JSON blob with the validated body + ip/ua/lookbook_id\n//\n// Why no auth: the URL itself is the shared secret (the partner gets the\n// lookbook page URL from the customer). For higher-stakes deployments, add a\n// session cookie or signed-link param here. The schema is forward-compatible.\nexport async function onRequestPost({ request, env, waitUntil }) {\n  let body;\n  try { body = await request.json(); }\n  catch { return json({ ok: false, error: \"invalid json\" }, 400); }\n\n  const rawBallotId = (body.ballot_id || \"\").toString().slice(0, 96);\n  const ballot_id = /^[A-Za-z0-9_-]{12,96}$/.test(rawBallotId)\n    ? rawBallotId\n    : crypto.randomUUID();\n  const voter   = (body.voter   || \"\").toString().slice(0, 60).trim() || \"anonymous\";\n  const comment = (body.comment || \"\").toString().slice(0, 1000);\n\n  const looks = {};\n  for (const [k, v] of Object.entries(body.looks || {})) {\n    if (/^look[0-9]+$/.test(k) && (v === \"up\" || v === \"down\")) looks[k] = v;\n  }\n  const items = {};\n  for (const [k, v] of Object.entries(body.items || {})) {\n    const sku = String(k).slice(0, 64);\n    if (sku && (v === \"up\" || v === \"down\")) items[sku] = v;\n  }\n\n  const ts   = new Date().toISOString();\n  const record = {\n    ballot_id, voter, comment, looks, items, ts,\n    ip: request.headers.get(\"CF-Connecting-IP\") || null,\n    ua: (request.headers.get(\"user-agent\") || \"\").slice(0, 200),\n    lookbook_id: env.LOOKBOOK_ID || \"unknown\",\n  };\n  const key = `vote:${record.lookbook_id}:ballot:${ballot_id}`;\n  await env.LOOKBOOK_VOTES.put(key, JSON.stringify(record));\n  const broadcast = notifyVoteRoom(env, { type: \"vote\", ts, lookbook_id: record.lookbook_id });\n  if (typeof waitUntil === \"function\") waitUntil(broadcast);\n  else await broadcast;\n  return json({ ok: true, key, ts, ballot_id });\n}\n\nasync function notifyVoteRoom(env, payload) {\n  if (!env.VOTE_ROOM || !env.LOOKBOOK_ID) return false;\n  try {\n    const id = env.VOTE_ROOM.idFromName(env.LOOKBOOK_ID);\n    const room = env.VOTE_ROOM.get(id);\n    const response = await room.fetch(\"https://vote-room.internal/broadcast\", {\n      method: \"POST\",\n      headers: { \"content-type\": \"application/json\" },\n      body: JSON.stringify(payload),\n    });\n    return response.ok;\n  } catch {\n    return false;\n  }\n}\n\nfunction json(obj, status = 200) {\n  return new Response(JSON.stringify(obj), {\n    status,\n    headers: { \"content-type\": \"application/json\", \"cache-control\": \"no-store\" },\n  });\n}\n" as const
export const VOTES_GET_FUNCTION = "// GET /api/votes — returns a public-safe live tally for one lookbook.\n//\n// No auth: the URL is the shared secret. Because the page itself polls this\n// endpoint for live indicators, the response intentionally omits IP and UA.\n// The handler uses a short edge-cache window so many viewers can watch the\n// same tally without every browser forcing a full KV scan.\nexport async function onRequestGet({ request, env }) {\n  const url = new URL(request.url);\n  const cacheable = url.searchParams.get(\"fresh\") !== \"1\";\n  const cacheKey = new Request(`${url.origin}${url.pathname}?lookbook=${encodeURIComponent(env.LOOKBOOK_ID || \"unknown\")}`);\n\n  if (cacheable && typeof caches !== \"undefined\") {\n    const cached = await caches.default.match(cacheKey);\n    if (cached) return cached;\n  }\n\n  const prefix = `vote:${env.LOOKBOOK_ID || \"unknown\"}:`;\n  const out = [];\n  let cursor;\n  while (true) {\n    const opts = { prefix };\n    if (cursor) opts.cursor = cursor;\n    const list = await env.LOOKBOOK_VOTES.list(opts);\n    for (const k of list.keys || []) {\n      const v = await env.LOOKBOOK_VOTES.get(k.name);\n      if (!v) continue;\n      try {\n        const parsed = JSON.parse(v);\n        if (parsed && typeof parsed === \"object\") out.push(parsed);\n      } catch {}\n    }\n    if (list.list_complete || !list.cursor) break;\n    cursor = list.cursor;\n  }\n\n  const counted = out\n    .filter(hasVotes)\n    .sort((a, b) => String(b.ts || \"\").localeCompare(String(a.ts || \"\")));\n\n  const tally = {\n    count: counted.length,\n    last_vote_ts: counted[0]?.ts || null,\n    generated_at: new Date().toISOString(),\n    looks: {},\n    items: {},\n    voters: [],\n    recent: [],\n    activity: activityBuckets(counted),\n  };\n  const bucket = (map, key) => (\n    map[key] ||= { up: 0, down: 0, total: 0, score: 0, up_voters: [], down_voters: [] }\n  );\n\n  for (const r of counted) {\n    if (!r || typeof r !== \"object\") continue;\n    for (const [look, v] of Object.entries(r.looks || {})) {\n      if (v === \"up\" || v === \"down\") countVote(bucket(tally.looks, look), v, r);\n    }\n    for (const [sku, v] of Object.entries(r.items || {})) {\n      if (v === \"up\" || v === \"down\") countVote(bucket(tally.items, sku), v, r);\n    }\n    const safe = {\n      voter: r.voter, ts: r.ts, comment: r.comment,\n      looks: r.looks, items: r.items,\n    };\n    tally.voters.push(safe);\n    if (String(r.comment || \"\").trim()) tally.recent.push(safe);\n  }\n  tally.recent = tally.recent.slice(0, 8);\n\n  const response = new Response(JSON.stringify({ ok: true, tally, votes: tally.voters }, null, 2), {\n    headers: {\n      \"content-type\": \"application/json\",\n      \"cache-control\": \"public, max-age=2, s-maxage=2, stale-while-revalidate=8\",\n    },\n  });\n  if (cacheable && typeof caches !== \"undefined\") {\n    try { await caches.default.put(cacheKey, response.clone()); } catch {}\n  }\n  return response;\n}\n\nfunction hasVotes(record) {\n  return Object.keys(record?.looks || {}).length > 0 || Object.keys(record?.items || {}).length > 0;\n}\n\nfunction countVote(bucket, vote, record) {\n  bucket[vote] += 1;\n  bucket.total += 1;\n  bucket.score = bucket.up - bucket.down;\n  const list = vote === \"up\" ? bucket.up_voters : bucket.down_voters;\n  if (list.length < 24) {\n    list.push({ voter: displayName(record.voter), comment: displayComment(record.comment), ts: record.ts });\n  }\n}\n\nfunction displayName(value) {\n  return String(value || \"anonymous\").trim().slice(0, 60) || \"anonymous\";\n}\n\nfunction displayComment(value) {\n  return String(value || \"\").trim().slice(0, 240);\n}\n\nfunction activityBuckets(records) {\n  const now = Date.now();\n  const buckets = [];\n  for (let i = 4; i >= 0; i--) {\n    const start = now - (i + 1) * 60_000;\n    const end = now - i * 60_000;\n    buckets.push({ start: new Date(start).toISOString(), count: 0 });\n    for (const r of records) {\n      const t = Date.parse(r.ts || \"\");\n      if (Number.isFinite(t) && t >= start && t < end) buckets[buckets.length - 1].count += 1;\n    }\n  }\n  return buckets;\n}\n" as const
export const VOTES_LIVE_FUNCTION = "// GET /api/votes/live - WebSocket upgrade endpoint for real-time tally fanout.\n//\n// The Durable Object is deployed as a sibling Worker and bound into Pages via\n// wrangler.toml. KV remains the durable source of truth; this endpoint only\n// attaches the browser to the per-lookbook vote room.\nexport async function onRequestGet({ request, env }) {\n  if (!env.VOTE_ROOM || !env.LOOKBOOK_ID) {\n    return json({ ok: false, error: \"VOTE_ROOM binding missing\" }, 503);\n  }\n  const upgrade = request.headers.get(\"Upgrade\") || \"\";\n  if (upgrade.toLowerCase() !== \"websocket\") {\n    return new Response(\"Expected WebSocket upgrade\", {\n      status: 426,\n      headers: { \"content-type\": \"text/plain\", \"upgrade\": \"websocket\" },\n    });\n  }\n\n  const id = env.VOTE_ROOM.idFromName(env.LOOKBOOK_ID);\n  return env.VOTE_ROOM.get(id).fetch(request);\n}\n\nfunction json(obj, status = 200) {\n  return new Response(JSON.stringify(obj), {\n    status,\n    headers: { \"content-type\": \"application/json\", \"cache-control\": \"no-store\" },\n  });\n}\n" as const
export const VOTE_ROOM_WORKER = "// Durable Object vote room for Cloudflare Pages lookbooks.\n//\n// The Pages POST function writes the ballot to KV, then pings this room. The\n// room scans KV once, builds the public-safe tally, and broadcasts that tally\n// to all connected browsers over WebSockets.\nexport class VoteRoom {\n  constructor(ctx, env) {\n    this.ctx = ctx;\n    this.env = env;\n    this.cachedText = null;\n    this.cachedAt = 0;\n  }\n\n  async fetch(request) {\n    const url = new URL(request.url);\n    const upgrade = request.headers.get(\"Upgrade\") || \"\";\n    if (upgrade.toLowerCase() === \"websocket\") {\n      const pair = new WebSocketPair();\n      const [client, server] = Object.values(pair);\n      this.ctx.acceptWebSocket(server);\n      this.sendTally(server, false).catch(() => {});\n      return new Response(null, { status: 101, webSocket: client });\n    }\n\n    if (request.method === \"POST\" && url.pathname.endsWith(\"/broadcast\")) {\n      const text = await this.tallyText(true);\n      let sent = 0;\n      for (const socket of this.ctx.getWebSockets()) {\n        try {\n          socket.send(text);\n          sent += 1;\n        } catch {}\n      }\n      return json({ ok: true, sent });\n    }\n\n    return json({ ok: false, error: \"not found\" }, 404);\n  }\n\n  async webSocketMessage(ws, message) {\n    if (String(message || \"\").toLowerCase() === \"ping\") {\n      ws.send(JSON.stringify({ type: \"pong\", ts: new Date().toISOString() }));\n      return;\n    }\n    if (String(message || \"\").toLowerCase() === \"refresh\") {\n      await this.sendTally(ws, true);\n    }\n  }\n\n  webSocketClose() {}\n  webSocketError() {}\n\n  async sendTally(socket, force) {\n    socket.send(await this.tallyText(force));\n  }\n\n  async tallyText(force) {\n    const now = Date.now();\n    if (!force && this.cachedText && now - this.cachedAt < 1000) return this.cachedText;\n    const tally = await loadTally(this.env);\n    this.cachedText = JSON.stringify({\n      type: \"tally\",\n      ok: true,\n      tally,\n      votes: tally.voters,\n    });\n    this.cachedAt = now;\n    return this.cachedText;\n  }\n}\n\nexport default {\n  fetch() {\n    return json({ ok: true, service: \"buckmason-vote-room\" });\n  },\n};\n\nasync function loadTally(env) {\n  const prefix = `vote:${env.LOOKBOOK_ID || \"unknown\"}:`;\n  const out = [];\n  let cursor;\n  while (true) {\n    const opts = { prefix };\n    if (cursor) opts.cursor = cursor;\n    const list = await env.LOOKBOOK_VOTES.list(opts);\n    for (const k of list.keys || []) {\n      const value = await env.LOOKBOOK_VOTES.get(k.name);\n      if (!value) continue;\n      try {\n        const parsed = JSON.parse(value);\n        if (parsed && typeof parsed === \"object\") out.push(parsed);\n      } catch {}\n    }\n    if (list.list_complete || !list.cursor) break;\n    cursor = list.cursor;\n  }\n\n  const counted = out\n    .filter(hasVotes)\n    .sort((a, b) => String(b.ts || \"\").localeCompare(String(a.ts || \"\")));\n  const tally = {\n    count: counted.length,\n    last_vote_ts: counted[0]?.ts || null,\n    generated_at: new Date().toISOString(),\n    looks: {},\n    items: {},\n    voters: [],\n    recent: [],\n    activity: activityBuckets(counted),\n  };\n  const bucket = (map, key) => (\n    map[key] ||= { up: 0, down: 0, total: 0, score: 0, up_voters: [], down_voters: [] }\n  );\n\n  for (const record of counted) {\n    if (!record || typeof record !== \"object\") continue;\n    for (const [look, vote] of Object.entries(record.looks || {})) {\n      if (vote === \"up\" || vote === \"down\") countVote(bucket(tally.looks, look), vote, record);\n    }\n    for (const [sku, vote] of Object.entries(record.items || {})) {\n      if (vote === \"up\" || vote === \"down\") countVote(bucket(tally.items, sku), vote, record);\n    }\n    const safe = {\n      voter: record.voter,\n      ts: record.ts,\n      comment: record.comment,\n      looks: record.looks,\n      items: record.items,\n    };\n    tally.voters.push(safe);\n    if (String(record.comment || \"\").trim()) tally.recent.push(safe);\n  }\n  tally.recent = tally.recent.slice(0, 8);\n  return tally;\n}\n\nfunction hasVotes(record) {\n  return Object.keys(record?.looks || {}).length > 0 || Object.keys(record?.items || {}).length > 0;\n}\n\nfunction countVote(bucket, vote, record) {\n  bucket[vote] += 1;\n  bucket.total += 1;\n  bucket.score = bucket.up - bucket.down;\n  const list = vote === \"up\" ? bucket.up_voters : bucket.down_voters;\n  if (list.length < 24) {\n    list.push({ voter: displayName(record.voter), comment: displayComment(record.comment), ts: record.ts });\n  }\n}\n\nfunction displayName(value) {\n  return String(value || \"anonymous\").trim().slice(0, 60) || \"anonymous\";\n}\n\nfunction displayComment(value) {\n  return String(value || \"\").trim().slice(0, 240);\n}\n\nfunction activityBuckets(records) {\n  const now = Date.now();\n  const buckets = [];\n  for (let i = 4; i >= 0; i--) {\n    const start = now - (i + 1) * 60_000;\n    const end = now - i * 60_000;\n    buckets.push({ start: new Date(start).toISOString(), count: 0 });\n    for (const record of records) {\n      const t = Date.parse(record.ts || \"\");\n      if (Number.isFinite(t) && t >= start && t < end) buckets[buckets.length - 1].count += 1;\n    }\n  }\n  return buckets;\n}\n\nfunction json(obj, status = 200) {\n  return new Response(JSON.stringify(obj), {\n    status,\n    headers: { \"content-type\": \"application/json\", \"cache-control\": \"no-store\" },\n  });\n}\n" as const
